#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> divisors;
    for(int i = 1; i <= n; i++){
        if(n % i == 0){
            divisors.push_back(i);
        }
    }
    cout << divisors.size() << endl;
    sort(divisors.begin(), divisors.end());
    for(int d : divisors){
        cout << d << endl;
    }
    return 0;
}
